import AppKit
import Foundation

class AppDelegate: NSObject, NSApplicationDelegate {
    var statusItem: NSStatusItem!
    var projectTimer: Timer?
    var currentProject: String = ""
    var screenIsOn: Bool = true

    let firstOnKey = "firstScreenOnTime"
    let projectKey = "currentProject"

    func applicationDidFinishLaunching(_ notification: Notification) {
        // Restore last project name across launches
        currentProject = UserDefaults.standard.string(forKey: projectKey) ?? ""

        setupStatusItem()
        setupScreenMonitoring()
        recordScreenOn()
        scheduleProjectTimer()
    }

    // MARK: - Status Item

    func setupStatusItem() {
        statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
        if let button = statusItem.button {
            button.title = "⏱"
            button.action = #selector(showMenu)
            button.target = self
        }
    }

    @objc func showMenu() {
        let menu = NSMenu()

        // First screen-on today
        if let firstOn = loadFirstOnTime() {
            let formatter = DateFormatter()
            formatter.timeStyle = .short
            let item = NSMenuItem(title: "First on today: \(formatter.string(from: firstOn))", action: nil, keyEquivalent: "")
            menu.addItem(item)
        } else {
            menu.addItem(NSMenuItem(title: "First on today: —", action: nil, keyEquivalent: ""))
        }

        // Current project
        let projLabel = currentProject.isEmpty ? "No project set" : "Project: \(currentProject)"
        menu.addItem(NSMenuItem(title: projLabel, action: nil, keyEquivalent: ""))

        menu.addItem(NSMenuItem.separator())

        let setItem = NSMenuItem(title: "Set project…", action: #selector(askForProjectManually), keyEquivalent: "p")
        setItem.target = self
        menu.addItem(setItem)

        menu.addItem(NSMenuItem.separator())

        let quitItem = NSMenuItem(title: "Quit", action: #selector(NSApplication.terminate(_:)), keyEquivalent: "q")
        menu.addItem(quitItem)

        statusItem.menu = menu
        statusItem.button?.performClick(nil)
        statusItem.menu = nil
    }

    // MARK: - Screen Monitoring

    func setupScreenMonitoring() {
        let nc = NSWorkspace.shared.notificationCenter
        nc.addObserver(self,
                       selector: #selector(screenWoke),
                       name: NSWorkspace.screensDidWakeNotification,
                       object: nil)
        nc.addObserver(self,
                       selector: #selector(screenSlept),
                       name: NSWorkspace.screensDidSleepNotification,
                       object: nil)
    }

    @objc func screenWoke() {
        screenIsOn = true
        recordScreenOn()
    }

    @objc func screenSlept() {
        screenIsOn = false
    }

    func recordScreenOn() {
        let now = Date()
        let defaults = UserDefaults.standard

        if let stored = defaults.object(forKey: firstOnKey) as? Date,
           Calendar.current.isDateInToday(stored) {
            return // Already recorded for today
        }

        defaults.set(now, forKey: firstOnKey)
    }

    func loadFirstOnTime() -> Date? {
        guard let stored = UserDefaults.standard.object(forKey: firstOnKey) as? Date,
              Calendar.current.isDateInToday(stored) else {
            return nil
        }
        return stored
    }

    // MARK: - Project Timer

    func scheduleProjectTimer() {
        projectTimer = Timer.scheduledTimer(withTimeInterval: 15 * 60, repeats: true) { [weak self] _ in
            guard let self, self.screenIsOn else { return }
            self.askForProject(isAutoPrompt: true)
        }
        RunLoop.main.add(projectTimer!, forMode: .common)
    }

    @objc func askForProjectManually() {
        askForProject(isAutoPrompt: false)
    }

    func askForProject(isAutoPrompt: Bool) {
        DispatchQueue.main.async {
            let alert = NSAlert()
            alert.messageText = isAutoPrompt ? "What are you working on?" : "Set current project"
            if isAutoPrompt {
                alert.informativeText = "15-minute check-in"
            }
            alert.alertStyle = .informational
            alert.addButton(withTitle: "Save")
            alert.addButton(withTitle: "Skip")

            let input = NSTextField(frame: NSRect(x: 0, y: 0, width: 280, height: 24))
            input.placeholderString = "Project name…"
            if !self.currentProject.isEmpty {
                input.stringValue = self.currentProject
            }
            alert.accessoryView = input

            NSApp.activate(ignoringOtherApps: true)

            if alert.runModal() == .alertFirstButtonReturn {
                let val = input.stringValue.trimmingCharacters(in: .whitespaces)
                if !val.isEmpty {
                    self.currentProject = val
                    UserDefaults.standard.set(val, forKey: self.projectKey)
                }
            }
        }
    }
}

