import AppKit
import Foundation

struct ScreenEvent: Codable {
    enum Kind: String, Codable { case on, off }
    let kind: Kind
    let time: Date
}

class AppDelegate: NSObject, NSApplicationDelegate {
    var statusItem: NSStatusItem!
    var projectTimer: Timer?
    var currentProject: String = ""

    let eventsKey = "screenEvents"
    let projectKey = "currentProject"

    func applicationDidFinishLaunching(_ notification: Notification) {
        currentProject = UserDefaults.standard.string(forKey: projectKey) ?? ""
        setupStatusItem()
        setupScreenMonitoring()
        recordEvent(.on)          // Screen is on when app starts
        scheduleProjectTimer()
    }

    // MARK: - Events Storage

    func loadTodayEvents() -> [ScreenEvent] {
        guard let data = UserDefaults.standard.data(forKey: eventsKey),
              let events = try? JSONDecoder().decode([ScreenEvent].self, from: data) else {
            return []
        }
        return events.filter { Calendar.current.isDateInToday($0.time) }
    }

    func saveEvents(_ events: [ScreenEvent]) {
        if let data = try? JSONEncoder().encode(events) {
            UserDefaults.standard.set(data, forKey: eventsKey)
        }
    }

    func recordEvent(_ kind: ScreenEvent.Kind) {
        var events = loadTodayEvents()

        // Avoid duplicate consecutive same-kind events
        if let last = events.last, last.kind == kind {
            return
        }

        events.append(ScreenEvent(kind: kind, time: Date()))
        saveEvents(events)
    }

    // MARK: - Time Calculation

    func totalOnTime(events: [ScreenEvent]) -> TimeInterval {
        var total: TimeInterval = 0
        var lastOn: Date?

        for event in events {
            switch event.kind {
            case .on:
                lastOn = event.time
            case .off:
                if let on = lastOn {
                    total += event.time.timeIntervalSince(on)
                    lastOn = nil
                }
            }
        }

        // Screen still on — count up to now
        if let on = lastOn {
            total += Date().timeIntervalSince(on)
        }

        return total
    }

    func formatDuration(_ interval: TimeInterval) -> String {
        let h = Int(interval) / 3600
        let m = (Int(interval) % 3600) / 60
        if h > 0 {
            return "\(h)h \(m)m"
        }
        return "\(m)m"
    }

    // MARK: - Status Item

    func setupStatusItem() {
        statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
        if let button = statusItem.button {
            button.title = "⏱"
            button.action = #selector(showMenu)
            button.target = self
        }
    }

    @objc func showMenu() {
        let events = loadTodayEvents()
        let menu = NSMenu()

        let timeFmt = DateFormatter()
        timeFmt.timeStyle = .short
        timeFmt.dateStyle = .none

        // Total on-time
        let total = totalOnTime(events: events)
        let totalItem = NSMenuItem(title: "Total on today: \(formatDuration(total))", action: nil, keyEquivalent: "")
        totalItem.isEnabled = false
        menu.addItem(totalItem)

        // First on time
        if let first = events.first(where: { $0.kind == .on }) {
            let item = NSMenuItem(title: "First on: \(timeFmt.string(from: first.time))", action: nil, keyEquivalent: "")
            item.isEnabled = false
            menu.addItem(item)
        }

        menu.addItem(NSMenuItem.separator())

        // All events
        if events.isEmpty {
            let item = NSMenuItem(title: "No events yet", action: nil, keyEquivalent: "")
            item.isEnabled = false
            menu.addItem(item)
        } else {
            for event in events {
                let arrow = event.kind == .on ? "▶ on " : "■ off"
                let item = NSMenuItem(title: "\(arrow)  \(timeFmt.string(from: event.time))", action: nil, keyEquivalent: "")
                item.isEnabled = false
                menu.addItem(item)
            }
        }

        menu.addItem(NSMenuItem.separator())

        // Current project
        let projLabel = currentProject.isEmpty ? "No project set" : "Project: \(currentProject)"
        let projItem = NSMenuItem(title: projLabel, action: nil, keyEquivalent: "")
        projItem.isEnabled = false
        menu.addItem(projItem)

        let setItem = NSMenuItem(title: "Set project…", action: #selector(askForProjectManually), keyEquivalent: "p")
        setItem.target = self
        menu.addItem(setItem)

        menu.addItem(NSMenuItem.separator())
        menu.addItem(withTitle: "Quit", action: #selector(NSApplication.terminate(_:)), keyEquivalent: "q")

        statusItem.menu = menu
        statusItem.button?.performClick(nil)
        statusItem.menu = nil
    }

    // MARK: - Screen Monitoring

    func setupScreenMonitoring() {
        let nc = NSWorkspace.shared.notificationCenter
        nc.addObserver(self, selector: #selector(screenWoke),
                       name: NSWorkspace.screensDidWakeNotification, object: nil)
        nc.addObserver(self, selector: #selector(screenSlept),
                       name: NSWorkspace.screensDidSleepNotification, object: nil)
    }

    @objc func screenWoke() { recordEvent(.on) }
    @objc func screenSlept() { recordEvent(.off) }

    // MARK: - Project Timer

    func scheduleProjectTimer() {
        projectTimer = Timer.scheduledTimer(withTimeInterval: 15 * 60, repeats: true) { [weak self] _ in
            guard let self else { return }
            let events = self.loadTodayEvents()
            // Only prompt if screen is currently on (last event is .on or no .off after last .on)
            if events.last?.kind != .off {
                self.askForProject(isAutoPrompt: true)
            }
        }
        RunLoop.main.add(projectTimer!, forMode: .common)
    }

    @objc func askForProjectManually() {
        askForProject(isAutoPrompt: false)
    }

    func askForProject(isAutoPrompt: Bool) {
        DispatchQueue.main.async {
            let alert = NSAlert()
            alert.messageText = isAutoPrompt ? "What are you working on?" : "Set current project"
            if isAutoPrompt { alert.informativeText = "15-minute check-in" }
            alert.alertStyle = .informational
            alert.addButton(withTitle: "Save")
            alert.addButton(withTitle: "Skip")

            let input = NSTextField(frame: NSRect(x: 0, y: 0, width: 280, height: 24))
            input.placeholderString = "Project name…"
            if !self.currentProject.isEmpty { input.stringValue = self.currentProject }
            alert.accessoryView = input

            NSApp.activate(ignoringOtherApps: true)

            if alert.runModal() == .alertFirstButtonReturn {
                let val = input.stringValue.trimmingCharacters(in: .whitespaces)
                if !val.isEmpty {
                    self.currentProject = val
                    UserDefaults.standard.set(val, forKey: self.projectKey)
                }
            }
        }
    }
}

