            let screenIsOn = data.screenEvents.filter { Calendar.current.isDateInToday($0.time) }.last?.kind != .off
            if screenIsOn { self.askForProject(isAutoPrompt: true) }
        }
        RunLoop.main.add(projectTimer!, forMode: .common)
    }

